namespace sv_091087f6614f45f4870dff1fd8e0aa6c.Services;

public sealed record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella and basil.", 30),
            new(2, "Pasta Carbonara", "Creamy Roman pasta with guanciale, egg, and pecorino.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp, peanuts, and tamarind sauce.", 35),
            new(5, "Green Curry", "Aromatic coconut curry with vegetables and Thai basil.", 40),
            new(6, "Tom Yum Soup", "Spicy and sour soup with lemongrass, galangal, and prawns.", 20),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple and cilantro.", 50),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and jalapeño.", 10),
            new(9, "Churros", "Fried dough pastries coated in cinnamon sugar.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@using sv_091087f6614f45f4870dff1fd8e0aa6c.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <h3>Recipes for Cuisine @CuisineId</h3>
    <ul>
        @foreach (var recipe in DisplayedRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <span class="text-muted">(@recipe.PrepTimeMinutes min)</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes =>
        Sort?.ToLowerInvariant() switch
        {
            "newest" => _recipes!.OrderByDescending(r => r.Id),
            "popular" => _recipes!.OrderBy(r => r.PrepTimeMinutes),
            _ => _recipes!
        };

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId)
        {
            // Only sort changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            token.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was superseded or component disposed — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

